def chunk_pad(lst, k):
    if not lst or k <= 0:
        return []

    padded_lst = [chunk + [None] * (k - len(chunk)) for chunk in chunks_of(lst, k)]
    return padded_lst

def chunks_of(lst, n):
    """Yield successive n-sized chunks from lst."""
    for i in range(0, len(lst), n):
        yield lst[i:i + n]
